#include <bits/stdc++.h>
using namespace std;

const int N=2e5+10;

int n,k,f[N];

int father(int x){
    return f[x]==x?x:f[x]=father(f[x]);
}

void Merge(int x,int y){
    int fx=father(x),fy=father(y);
    if(fx!=fy)
        f[fy]=fx;
}

int main(){
    scanf("%d%d",&n,&k);
    for(int i=1;i<=3*n;i++)
        f[i]=i;
    int res=0;
    for(int i=1;i<=k;i++){
        int op,x,y;
        scanf("%d%d%d",&op,&x,&y);
        if(max(x,y)>n){
            res++;
            continue;
        }
        if(op==1){
        	if(father(x)==father(y+n) || father(x)==father(y+n+n))
        		res++;
        	else
            	Merge(x,y),Merge(x+n,y+n),Merge(x+n+n,y+n+n);
        }else{
            if(father(x)==father(y) || father(x)==father(y+n))
                res++;
            else
                Merge(x+n,y),Merge(x+n+n,y+n),Merge(x,y+n+n);
        }
    }
    printf("%d",res);
    return 0;
}
